import pickle
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load trained model and vectorizer
model_file = 'model.pkl'
vectorizer_file = 'vectorizer.pkl'

try:
    with open(model_file, 'rb') as file:
        model = pickle.load(file)
    with open(vectorizer_file, 'rb') as file:
        vectorizer = pickle.load(file)
except FileNotFoundError:
    # Train model if not exists
    emails = [
        ('This is a test email', 0),
        ('Make money fast', 1),
        ('Buy now and get discount', 1),
        # Add more data here...
    ]

    X = [email[0] for email in emails]
    y = [email[1] for email in emails]

    vectorizer = CountVectorizer()
    X_vectorized = vectorizer.fit_transform(X)

    model = LogisticRegression()
    model.fit(X_vectorized, y)

    with open(model_file, 'wb') as file:
        pickle.dump(model, file)
    with open(vectorizer_file, 'wb') as file:
        pickle.dump(vectorizer, file)

@app.route('/classify', methods=['POST'])
def classify_email():
    data = request.json
    if 'email' not in data:
        return jsonify({'error': 'Missing email text'}), 400

    email_text = data['email']
    vectorized_text = vectorizer.transform([email_text])
    spam_probability = model.predict_proba(vectorized_text)[:, 1][0]

    return jsonify({'spam_probability': spam_probability})

if __name__ == '__main__':
    app.run(debug=True)